#include<bits/stdc++.h>
using namespace std;
int main() {
	int t, n, m, x, y, d, k, ans;
	string a[1010];

	cin >> t;
	for (int i = 0; i < t; i++) {
		int  b[1100][1100] = {{0}};

		cin >> n >> m >> k >> x >> y >> d;
		for (int j = 0; j < n; j++) {
			cin >> a[j];
		}

		ans = 1;
		b[x][y] = 1;


		for (int j = 0; j < k; j++) {
			//	cout << a[1][4 ] << endl;
			if (d == 0) {
				if (  y == m) {
					d =  (d + 1) % 4;

					continue;
				}

				if ( a[x - 1 ][y ] != '.') {
					d = (d + 1) % 4;

					continue;
				}
				if (b[x][y + 1] == 0) {
					ans++;
					//	cout << b[x][y + 1] << endl;

				}
				b[x][y + 1] = 1;
				y = y + 1;
			} else if (d == 1) {
				if (  x == n) {
					d =  (d + 1) % 4;

					continue;
				}
				if ( a[x ][y - 1] != '.') {
					d =  (d + 1) % 4;

					continue;
				}
				if (b[x + 1][y] == 0) {
					//cout<<b[x][y + 1]<< endl;
					ans++;
				}
				b[x + 1][y] = 1;
				x = x + 1;
			} else if (d == 2) {
				if (  y == 1) {
					d =  (d + 1) % 4;

					continue;
				}

				if (  a[x - 1][y - 2] != '.') {
					d =  (d + 1) % 4;

					continue;
				}
				if (b[x][y - 1] == 0) {
					//	cout << b[x][y + 1] << endl;
					ans++;
				}
				b[x][y - 1] = 1;
				y = y - 1;
			} else if (d == 3) {
				if (  x == 1) {
					d =  (d + 1) % 4;

					continue;
				}
				if ( a[x - 2][y - 1] != '.') {
					d =  (d + 1) % 4;

					continue;
				}
				if (b[x - 1][y] == 0) {
					ans++;
					//	cout << b[x][y + 1] << endl;
				}
				b[x - 1][y] = 1;
				x = x - 1;
			}
		}


		cout << ans << endl;
	}
}
